:root {
  --bg-card: #1a1a2e;
  --bg-item: #16213e;
  --bg-winner: #0f3460;
  --accent: #e94560;
  --accent-light: #ff6b6b;
  --bar-default: #2a4a7f;
  --bar-winner: #e94560;
  --text-primary: #eaeaea;
  --text-secondary: #8892a4;
  --text-rank: #ffffff;
  --tag-bg: #0d2240;
  --tag-text: #7aafd4;
  --crown-col: #f5c518;
  --footer-bg: #101026;
  --btn-bg: #e94560;
  --btn-text: #ffffff;
  --border-winner: #e94560;
  --border-item: #1e2d4a;
}

.board {
  width: 520px;
  background: var(--bg-card);
  border-radius: 16px;
  overflow: hidden;
  margin: 0 auto;
}

.board-header {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 16px 20px;
  background: var(--bg-item);
  border-bottom: 2px solid var(--border-item);
}

.board-icon {
  font-size: 28px;
  line-height: 1;
}

.board-title h2 {
  font-size: 18px;
  font-weight: 700;
  color: var(--text-primary);
  margin: 0;
  line-height: 1.2;
}

.board-title p {
  font-size: 12px;
  color: var(--text-secondary);
  margin: 0;
  line-height: 1.4;
}

.board-date {
  margin-left: auto;
  font-size: 11px;
  font-weight: 700;
  color: var(--accent);
  letter-spacing: 0.08em;
  background: var(--tag-bg);
  padding: 4px 10px;
  border-radius: 20px;
  border: 1px solid var(--border-item);
}

.movie-list {
  display: flex;
  flex-direction: column;
  gap: 0;
  padding: 12px 16px;
  gap: 8px;
}

.movie-item {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 10px 14px;
  background: var(--bg-item);
  border-radius: 10px;
  border: 1.5px solid var(--border-item);
}

.movie-item.winner {
  background: var(--bg-winner);
  border-color: var(--border-winner);
}

.rank {
  font-size: 14px;
  font-weight: 800;
  color: var(--text-rank);
  width: 18px;
  text-align: center;
  flex-shrink: 0;
}

.movie-info {
  display: flex;
  flex-direction: column;
  gap: 4px;
  flex: 0 0 140px;
}

.movie-title {
  font-size: 13px;
  font-weight: 700;
  color: var(--text-primary);
  line-height: 1.2;
}

.tags {
  display: flex;
  gap: 4px;
}

.tag {
  font-size: 10px;
  font-weight: 600;
  color: var(--tag-text);
  background: var(--tag-bg);
  padding: 2px 6px;
  border-radius: 4px;
}

.vote-bar-wrap {
  flex: 1;
  height: 8px;
  background: var(--bar-default);
  border-radius: 4px;
  overflow: hidden;
}

.vote-bar {
  height: 100%;
  width: var(--pct);
  background: var(--bar-default);
  border-radius: 4px;
}

.movie-item.winner .vote-bar {
  background: var(--bar-winner);
}

.vote-pct {
  font-size: 13px;
  font-weight: 700;
  color: var(--text-primary);
  flex-shrink: 0;
  width: 34px;
  text-align: right;
}

.crown {
  font-size: 14px;
  flex-shrink: 0;
  width: 18px;
  text-align: center;
  color: var(--crown-col);
}

.board-footer {
  display: flex;
  align-items: center;
  gap: 16px;
  padding: 12px 20px;
  background: var(--footer-bg);
  border-top: 2px solid var(--border-item);
}

.stat {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2px;
}

.stat-num {
  font-size: 16px;
  font-weight: 800;
  color: var(--text-primary);
  line-height: 1;
}

.stat-label {
  font-size: 10px;
  font-weight: 600;
  color: var(--text-secondary);
  text-transform: uppercase;
  letter-spacing: 0.06em;
}

.divider-v {
  width: 1px;
  height: 28px;
  background: var(--border-item);
}

.vote-btn {
  margin-left: auto;
  background: var(--btn-bg);
  color: var(--btn-text);
  border: none;
  border-radius: 8px;
  padding: 8px 20px;
  font-size: 13px;
  font-weight: 700;
  cursor: pointer;
  letter-spacing: 0.04em;
}
